const STORAGE_KEY = "putirusu_v9_state";

let state = loadState();
let currentLessonIndex = 0;
let currentAudio = PHRASES[0];
let currentSpeaking = PHRASES[0];
let currentReview = null;
let currentExam = [];
let currentGame = "builder";

function loadState() {
    const base = {
        xp: 0,
        level: 1,
        hearts: 5,
        streak: 1,
        lastDate: new Date().toDateString(),
        onboarded: false,
        profile: {
            name: "",
            goal: "viagem",
            level: "iniciante"
        },
        completedLessons: [],
        reviewQueue: [],
        mistakes: [],
        notes: [],
        seen: {}
    };
    try {
        return {
            ...base,
            ...JSON.parse(localStorage.getItem(STORAGE_KEY) || "{}")
        };
    } catch {
        return base;
    }
}

function saveState() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
}

function cleanText(text) {
    return String(text || "").replace(/\s+/g, " ").trim();
}

function normalize(text) {
    return cleanText(text).toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
}

function toast(text) {
    const el = document.getElementById("toast");
    if (!el) return;
    el.textContent = text;
    el.classList.add("show");
    setTimeout(() => el.classList.remove("show"), 2200);
}

function addXP(amount) {
    state.xp += amount;
    state.level = Math.max(1, Math.floor(state.xp / 150) + 1);
    saveState();
    renderStats();
}

function loseHeart() {
    state.hearts = Math.max(0, state.hearts - 1);
    saveState();
    renderStats();
}

function addReview(item, reason) {
    const base = normalize(item.ru);
    const existing = state.reviewQueue.find(x => normalize(x.ru) === base);
    if (existing) {
        existing.count += 1;
        existing.reason = reason;
    } else {
        state.reviewQueue.push({
            ru: item.ru,
            pt: item.pt,
            pron: item.pron || transliterate(item.ru),
            cat: item.cat || "revisão",
            reason,
            count: 1
        });
    }
    saveState();
}

function speak(text, rate = 0.9) {
    const value = cleanText(text);
    if (!value) return;
    if (!("speechSynthesis" in window)) {
        toast("Som não disponível neste navegador");
        return;
    }
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(value);
    utterance.lang = "ru-RU";
    utterance.rate = rate;
    utterance.pitch = 1;
    window.speechSynthesis.speak(utterance);
}

function listen(callback) {
    const Recognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!Recognition) {
        toast("Microfone não disponível neste navegador");
        return;
    }
    const rec = new Recognition();
    rec.lang = "ru-RU";
    rec.interimResults = false;
    rec.maxAlternatives = 1;
    rec.onstart = () => toast("Fale agora em russo");
    rec.onerror = () => toast("Não consegui ouvir. Tente novamente");
    rec.onresult = event => callback(event.results[0][0].transcript);
    rec.start();
}

function transliterate(text) {
    const map = {
        А:"a",а:"a",Б:"b",б:"b",В:"v",в:"v",Г:"g",г:"g",Д:"d",д:"d",Е:"ye",е:"ye",Ё:"yo",ё:"yo",Ж:"j",ж:"j",З:"z",з:"z",И:"i",и:"i",Й:"y",й:"y",К:"k",к:"k",Л:"l",л:"l",М:"m",м:"m",Н:"n",н:"n",О:"o",о:"o",П:"p",п:"p",Р:"r",р:"r",С:"s",с:"s",Т:"t",т:"t",У:"u",у:"u",Ф:"f",ф:"f",Х:"kh",х:"kh",Ц:"ts",ц:"ts",Ч:"ch",ч:"ch",Ш:"sh",ш:"sh",Щ:"shch",щ:"shch",Ы:"y",ы:"y",Э:"e",э:"e",Ю:"yu",ю:"yu",Я:"ya",я:"ya",Ь:"",ь:"",Ъ:"",ъ:""
    };
    return String(text || "").split("").map(ch => map[ch] ?? ch).join("");
}

function allItems() {
    return [...VOCABULARY, ...PHRASES];
}

function findItem(query) {
    const q = normalize(query);
    if (!q) return null;
    return allItems().find(item => normalize(item.ru) === q || normalize(item.pt) === q || normalize(item.pron) === q)
        || allItems().find(item => normalize(item.ru).includes(q) || normalize(item.pt).includes(q) || normalize(item.pron).includes(q));
}

function itemFromRussian(text) {
    return findItem(text) || {
        ru: cleanText(text),
        pt: "conteúdo russo para estudar",
        pron: transliterate(text),
        cat: "texto"
    };
}

function randomFrom(list) {
    return list[Math.floor(Math.random() * list.length)];
}

function renderStats() {
    document.getElementById("xp-view").textContent = state.xp + " XP";
    document.getElementById("level-view").textContent = "Nível " + state.level;
    document.getElementById("hearts-view").textContent = "❤️".repeat(state.hearts) + "♡".repeat(5 - state.hearts);
    document.getElementById("streak-view").textContent = state.streak + " dias";
}

function setScreen(id) {
    document.querySelectorAll(".screen").forEach(screen => screen.classList.remove("active"));
    document.getElementById(id)?.classList.add("active");
    document.querySelectorAll("#main-nav button").forEach(btn => btn.classList.toggle("active", btn.dataset.screen === id));
    const titles = {
        dashboard: ["Painel", "Seu caminho para falar russo."],
        course: ["Curso", "Unidades do básico ao avançado."],
        teacher: ["Professor IA", "Explicações úteis e organizadas."],
        alphabet: ["Alfabeto", "Letras cirílicas com imagem e som."],
        audio: ["Áudio", "Escuta guiada com frases úteis."],
        writing: ["Escrita", "Treine cirílico, frases e textos."],
        speaking: ["Fala", "Use o microfone para praticar."],
        review: ["Revisão", "Prepare-se para as provas."],
        exams: ["Provas", "Teste seu conhecimento."],
        games: ["Jogos", "Pratique brincando."],
        dictionary: ["Dicionário", "Busca rápida sem bugs."],
        culture: ["Cultura", "História, folclore e culinária."],
        profile: ["Perfil", "Objetivo e progresso."]
    };
    document.getElementById("screen-title").textContent = titles[id]?.[0] || "PUTIRUSU";
    document.getElementById("screen-subtitle").textContent = titles[id]?.[1] || "";
    document.querySelector(".sidebar")?.classList.remove("open");
    window.scrollTo({ top: 0, behavior: "smooth" });
}

function studyHTML(item) {
    return `
        <div class="study-card">
            <h2>${item.ru}</h2>
            <div class="study-line"><strong>Tradução:</strong> ${item.pt}</div>
            <div class="study-line"><strong>Pronúncia:</strong> ${item.pron || transliterate(item.ru)}</div>
            <div class="study-line"><strong>Explicação:</strong> use esse conteúdo para dizer "${item.pt}". Primeiro ouça, depois repita, escreva e responda.</div>
            <div class="button-row">
                <button data-speak="${item.ru}">Ouvir</button>
                <button data-slow="${item.ru}">Devagar</button>
                <button data-add-review="${item.ru}">Salvar revisão</button>
            </div>
            <div class="exercise-box">
                <strong>Pergunta:</strong> Qual é a tradução de "${item.ru}"?
                <input data-answer="${item.pt}" placeholder="Digite a tradução">
                <button data-check-answer>Verificar</button>
                <div class="feedback"></div>
            </div>
        </div>
    `;
}

function wireStudy(container) {
    container.querySelectorAll("[data-speak]").forEach(btn => btn.onclick = () => speak(btn.dataset.speak));
    container.querySelectorAll("[data-slow]").forEach(btn => btn.onclick = () => speak(btn.dataset.slow, 0.65));
    container.querySelectorAll("[data-add-review]").forEach(btn => btn.onclick = () => {
        addReview(itemFromRussian(btn.dataset.addReview), "Salvo para revisar");
        toast("Adicionado à revisão");
    });
    container.querySelectorAll("[data-check-answer]").forEach(btn => btn.onclick = () => {
        const box = btn.closest(".exercise-box");
        const input = box.querySelector("input");
        const feedback = box.querySelector(".feedback");
        const ok = normalize(input.value) === normalize(input.dataset.answer);
        feedback.className = "feedback " + (ok ? "good" : "bad");
        feedback.textContent = ok ? "Certo! Você entendeu." : "Ainda não. Resposta correta: " + input.dataset.answer;
        ok ? addXP(10) : loseHeart();
    });
}

function renderCourse() {
    const levels = [...new Set(COURSE_UNITS.map(unit => unit.level))];
    const tabs = document.getElementById("course-tabs");
    tabs.innerHTML = levels.map(level => `<button data-level="${level}">${level}</button>`).join("");
    tabs.querySelectorAll("button").forEach(btn => btn.onclick = () => renderUnits(btn.dataset.level));
    renderUnits(levels[0]);
}

function renderUnits(level) {
    const host = document.getElementById("course-units");
    const units = COURSE_UNITS.filter(unit => unit.level === level);
    host.innerHTML = units.map(unit => {
        const index = COURSE_UNITS.indexOf(unit);
        const done = state.completedLessons.includes(index);
        return `
            <article class="lesson-card">
                <span class="eyebrow">${unit.level} · ${unit.theme}</span>
                <h3>${unit.title}</h3>
                <p>${unit.grammar}</p>
                <p>${unit.items.length} conteúdos com áudio e exercícios</p>
                <button data-open-lesson="${index}">${done ? "Revisar aula" : "Abrir aula"}</button>
            </article>
        `;
    }).join("");
    host.querySelectorAll("[data-open-lesson]").forEach(btn => btn.onclick = () => openLesson(Number(btn.dataset.openLesson)));
}

function openLesson(index) {
    currentLessonIndex = index;
    const unit = COURSE_UNITS[index];
    const host = document.getElementById("lesson-area");
    host.innerHTML = `
        <div class="lesson-card">
            <p class="eyebrow">${unit.level} · ${unit.theme}</p>
            <h2>${unit.title}</h2>
            <div class="study-line"><strong>Explicação da unidade:</strong> ${unit.grammar}</div>
            <div class="lesson-items">
                ${unit.items.map(text => studyHTML(itemFromRussian(text))).join("")}
            </div>
            <button id="finish-lesson">Concluir unidade</button>
        </div>
    `;
    wireStudy(host);
    document.getElementById("finish-lesson").onclick = () => {
        if (!state.completedLessons.includes(index)) {
            state.completedLessons.push(index);
        }
        addXP(55);
        saveState();
        toast("Unidade concluída");
        renderCourse();
        renderProfile();
    };
}

