function v10FindExpandedLessonByTheme(theme) {
    return V10_EXPANDED_LESSON_BANK.filter(item => normalize(item.theme) === normalize(theme));
}
function v10FindExpandedLessonByLevel(level) {
    return V10_EXPANDED_LESSON_BANK.filter(item => item.level === level);
}
function v10BuildExpandedReview(level) {
    const source = v10FindExpandedLessonByLevel(level || "A1").slice(0, 20);
    return source.map(item => ({
        ru: item.russian,
        pt: item.translation,
        pron: item.pronunciation,
        cat: item.theme
    }));
}
function v10ExpandedTeacherAnswer(query) {
    const q = normalize(query);
    const found = V10_EXPANDED_LESSON_BANK.find(item =>
        normalize(item.russian).includes(q) ||
        normalize(item.translation).includes(q) ||
        normalize(item.theme).includes(q)
    ) || V10_EXPANDED_LESSON_BANK[0];
    return `Russo: ${found.russian}
Tradução: ${found.translation}
Pronúncia: ${found.pronunciation}
Explicação: ${found.explanation}
Perguntas:
1. ${found.questions[0]}
2. ${found.questions[1]}
3. ${found.questions[2]}`;
}
